import { Routes } from "@angular/router";
import { URL_ACTION } from "src/app/core/enums";
import { ExamScheduleComponent } from "./exam-schedule/exam-schedule.component";
import { ExamScheduleAddComponent } from "./exam-schedule-add/exam-schedule-add.component";
import { ExamTypeComponent } from "./exam-type/exam-type.component";
import { ExamTypeAddComponent } from "./exam-type-add/exam-type-add.component";
import { GradeComponent } from "./grade/grade.component";
import { ResultComponent } from "./result/result.component";
import { ResultAddComponent } from "./result-add/result-add.component";

export const Routez: Routes = [
  // ✅ THIS is the missing piece
  {
    path: '',
    redirectTo: 'admin',
    pathMatch: 'full',
  },
  {
    path: 'exam-schedule',
    component: ExamScheduleComponent,
    data: {
      title: 'Exam Schedule',
      linkCreate: '/feature/exam/schedule-add',
      permission: [URL_ACTION.VIEW],
      layer: ['Exam', 'Exam Schedule'],
    },
  },
  {
    path: 'exam-schedule-add',
    component: ExamScheduleAddComponent,
    data: {
      title: 'Exam Schedule',
      linkList: '/feature/exam/schedule',
      permission: [URL_ACTION.ADD, URL_ACTION.EDIT, URL_ACTION.VIEW],
      layer: ['Exam', 'Exam Schedule', 'Add | Edit'],
    },
  },
  {
    path: 'exam-type',
    component: ExamTypeComponent,
    data: {
      title: 'Exam Type',
      linkCreate: '/feature/exam/type-add',
      permission: [URL_ACTION.VIEW],
      layer: ['Exam', 'Exam Type'],
    },
  },
  {
    path: 'exam-type-add',
    component: ExamTypeAddComponent,
    data: {
      title: 'Exam Type',
      linkList: '/feature/exam/type',
      permission: [URL_ACTION.ADD, URL_ACTION.EDIT, URL_ACTION.VIEW],
      layer: ['Exam', 'Exam Type', 'Add | Edit'],
    },
  },
  {
    path: 'grade',
    component: GradeComponent,
    data: {
      title: 'Grade',
      linkCreate: '/feature/exam/grade-add',
      permission: [URL_ACTION.VIEW],
      layer: ['Exam', 'Grade'],
    },
  },
  {
    path: 'grade-add',
    component: GradeComponent,
    data: {
      title: 'Grade',
      linkList: '/feature/exam/grade',
      permission: [URL_ACTION.ADD, URL_ACTION.EDIT, URL_ACTION.VIEW],
      layer: ['Exam', 'Grade', 'Add | Edit'],
    },
  },
  {
    path: 'result',
    component: ResultComponent,
    data: {
      title: 'Result',
      linkCreate: '/feature/exam/result-add',
      permission: [URL_ACTION.VIEW],
      layer: ['Exam', 'Result'],
    },
  },
  {
    path: 'result-add',
    component: ResultAddComponent,
    data: {
      title: 'Result',
      linkList: '/feature/exam/result',
      permission: [URL_ACTION.ADD, URL_ACTION.EDIT, URL_ACTION.VIEW],
      layer: ['Exam', 'Result', 'Add | Edit'],
    },
  },
];
